import{_ as n,C as o,o as s,c as l,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Austria Healthcare","description":"Healthcare and HRT access for transgender people in Austria","frontmatter":{"layout":"doc","title":"Austria Healthcare","description":"Healthcare and HRT access for transgender people in Austria"},"headers":[],"relativePath":"europe/austria/healthcare.md","filePath":"europe/austria/healthcare.md","lastUpdated":null}'),c={name:"europe/austria/healthcare.md"};function h(u,e,p,g,m,f){const t=o("Badge");return s(),l("div",null,[a(t,{variant:"yellow"},{default:r(()=>[...e[0]||(e[0]=[i("Mixed Model",-1)])]),_:1}),a(t,{variant:"green"},{default:r(()=>[...e[1]||(e[1]=[i("Informed Consent in Vienna",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-austria" tabindex="-1">Healthcare in Austria <a class="header-anchor" href="#healthcare-in-austria" aria-label="Permalink to &quot;Healthcare in Austria&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Austria has a mixed model for trans healthcare. The <strong>AKH Vienna (Allgemeines Krankenhaus)</strong> operates an informed consent approach, while other regions, particularly smaller cities and rural areas, may still require psychiatric gatekeeping.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><h3 id="vienna-—-akh-informed-consent" tabindex="-1">Vienna — AKH (Informed Consent) <a class="header-anchor" href="#vienna-—-akh-informed-consent" aria-label="Permalink to &quot;Vienna — AKH (Informed Consent)&quot;">​</a></h3><p>The <strong>Medical University of Vienna / AKH</strong> operates an informed consent model:</p><ul><li><strong>Gender outpatient clinic (Genderambulanz)</strong> at the Department of Gynaecology</li><li>Clinical psychologists and endocrinologists work together</li><li>Focus on patient autonomy</li><li>No mandatory psychiatric diagnosis</li><li>English-speaking staff available</li></ul><h3 id="process-at-akh-vienna" tabindex="-1">Process at AKH Vienna <a class="header-anchor" href="#process-at-akh-vienna" aria-label="Permalink to &quot;Process at AKH Vienna&quot;">​</a></h3><ol><li>Self-referral or GP referral to the Genderambulanz</li><li>Initial consultation: discussion of treatment goals, medical history</li><li>Psychological consultation (1-2 sessions — not diagnostic, but supportive)</li><li>Endocrinology consultation and blood tests</li><li>Informed consent form signed</li><li>HRT prescription — typically within 2-4 months of first contact</li><li>Regular follow-up every 3-6 months</li></ol><h3 id="regional-variations" tabindex="-1">Regional Variations <a class="header-anchor" href="#regional-variations" aria-label="Permalink to &quot;Regional Variations&quot;">​</a></h3><p>Outside Vienna, the model varies:</p><ul><li><strong>Graz</strong>: LKH Graz — Evaluation-based, psychiatric diagnosis often required</li><li><strong>Linz</strong>: Kepler University Hospital — Mixed approach</li><li><strong>Salzburg</strong>: Salzburg University Hospital — Gatekeeping more common</li><li><strong>Innsbruck</strong>: Medical University of Innsbruck — Limited trans services</li><li><strong>Smaller cities</strong>: Often require psychiatric referral, limited specialists</li></ul><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Model</th><th>Wait Times</th></tr></thead><tbody><tr><td>AKH Genderambulanz</td><td>Vienna</td><td>Informed consent</td><td>2-4 months</td></tr><tr><td>LKH Graz</td><td>Graz</td><td>Evaluation-based</td><td>3-6 months</td></tr><tr><td>Kepler University Hospital</td><td>Linz</td><td>Mixed</td><td>3-6 months</td></tr><tr><td>Salzburg University Hospital</td><td>Salzburg</td><td>Gatekeeping</td><td>4-8 months</td></tr><tr><td>Medical University Innsbruck</td><td>Innsbruck</td><td>Limited</td><td>4-8 months</td></tr></tbody></table><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU member state</strong> — EU prescription cross-border rules apply</li><li>EU/EEA prescriptions valid for up to 30 days</li><li>Austrian doctors may re-prescribe for ongoing treatment</li><li>Non-EU prescriptions require verification</li><li>German language prescriptions preferred; English accepted</li><li><strong>ÖGK (Österreichische Gesundheitskasse)</strong> covers trans-related care</li></ul><h2 id="insurance-coverage" tabindex="-1">Insurance Coverage <a class="header-anchor" href="#insurance-coverage" aria-label="Permalink to &quot;Insurance Coverage&quot;">​</a></h2><p>Austria has mandatory <strong>social health insurance (Krankenversicherung)</strong>:</p><ul><li><strong>ÖGK</strong> covers gender-affirming treatments</li><li>HRT medications covered with prescription (prescription fee ~€6-10 per item)</li><li>Surgery coverage requires medical necessity approval</li><li>Co-payment (Rezeptgebühr) is €6.50 per prescription (2024)</li><li>Annual cap on co-payments</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgeries available at AKH Vienna and some regional hospitals</li><li>Insurance covers surgeries after medical necessity established</li><li>Wait times: 6-12 months for consultation, 12-18 months for surgery</li><li>Top surgery: covered, wait 6-12 months</li><li>Bottom surgery: covered, wait 12-18 months</li><li>FFS: limited coverage</li></ul><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>AKH Genderambulanz</strong> — Integrated psychological support</li><li><strong>HOSI Wien</strong> — LGBTQ+ counselling and peer support</li><li><em><em>Trans</em> Austria</em>* — Community support groups</li><li>Private gender therapists: €80-150/session</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Typical Cost</th><th>Insurance Coverage</th></tr></thead><tbody><tr><td>GP visit</td><td>Covered</td><td>Full (e-card)</td></tr><tr><td>Endocrinology consult</td><td>Covered</td><td>Full</td></tr><tr><td>HRT (monthly)</td><td>€6-20/month</td><td>Prescription fee only</td></tr><tr><td>Blood tests</td><td>Covered</td><td>Full</td></tr><tr><td>Private therapy</td><td>€80-120/session</td><td>Partial (if approved)</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://akhwien.at/" target="_blank" rel="noreferrer">AKH Wien - Genderambulanz</a></li><li><a href="https://www.oegk.at/" target="_blank" rel="noreferrer">ÖGK - Austrian Health Insurance</a></li><li><a href="https://www.hosiwien.at/" target="_blank" rel="noreferrer">HOSI Wien</a></li><li><a href="https://trans-austria.org/" target="_blank" rel="noreferrer">Trans* Austria</a></li><li><a href="https://vimoe.at/" target="_blank" rel="noreferrer">VIMÖ</a></li></ul>',27))])}const v=n(c,[["render",h]]);export{y as __pageData,v as default};
